 42→// Suppress Vite's CSS preload errors in the Chrome extension content script context.
 43→// Dynamic imports (e.g., mermaid) trigger Vite's __vitePreload helper which tries to
 44→// create <link> elements with paths like "/assets/foo.css". In a content script, these
 45→// resolve to the web page origin (e.g., https://gemini.google.com/assets/foo.css)
 46→// instead of the extension, causing false "Unable to preload CSS" errors.
 47→// The CSS is already injected via contentStyle.css, so these preloads are unnecessary.
 48→window.addEventListener('vite:preloadError', (event) => {
 49→  event.preventDefault();
 50→});
 51→
 52→/**
 53→ * Staggered initialization to prevent "thundering herd" problem when multiple tabs
 54→ * are restored simultaneously (e.g., after browser restart).
 55→ *
 56→ * Background tabs get a random delay (3-8s) to distribute initialization load.
 57→ * Foreground tabs initialize immediately for good UX.
 58→ *
 59→ * This prevents triggering Google's rate limiting when restoring sessions with
 60→ * many Gemini tabs containing long conversations.
 61→ */
 62→
 63→// Initialization delay constants (in milliseconds)
 64→const HEAVY_FEATURE_INIT_DELAY = 100; // For resource-intensive features (Timeline, Folder)
 65→const LIGHT_FEATURE_INIT_DELAY = 50; // For lightweight features
 66→const BACKGROUND_TAB_MIN_DELAY = 3000; // Minimum delay for background tabs
 67→const BACKGROUND_TAB_MAX_DELAY = 8000; // Maximum delay for background tabs (3000 + 5000)
 68→
 69→let initialized = false;
 70→let initializationTimer: number | null = null;
 71→let folderManagerInstance: Awaited<ReturnType<typeof startFolderManager>> | null = null;
