115→function uid(): string {
116→  // FNV-1a-ish hash over timestamp + rand
117→  const seed = `${Date.now()}-${Math.random().toString(36).slice(2)}`;
118→  let h = 2166136261 >>> 0;
119→  for (let i = 0; i < seed.length; i++) {
120→    h ^= seed.charCodeAt(i);
121→    h = Math.imul(h, 16777619);
122→  }
123→  return (h >>> 0).toString(36);
124→}
