269→function computeAnchoredPosition(
270→  trigger: HTMLElement,
271→  panel: HTMLElement,
272→): { top: number; left: number } {
273→  const rect = trigger.getBoundingClientRect();
274→  const vw = window.innerWidth;
275→  const pad = 8;
276→  const panelW = Math.min(380, Math.max(300, panel.getBoundingClientRect().width || 320));
277→  const tentativeLeft = Math.min(vw - panelW - pad, Math.max(pad, rect.left + rect.width - panelW));
278→  const top = Math.max(pad, rect.top - (panel.getBoundingClientRect().height || 360) - 10);
279→  return { top, left: Math.round(tentativeLeft) };
280→}
