 1→import React, { useCallback, useEffect, useState } from 'react';
 2→
 3→export function useDarkMode() {
 4→  const [isDark, setIsDark] = useState(() => {
 5→    // Check saved preference first
 6→    const saved = localStorage.getItem('darkMode');
 7→    if (saved !== null) {
 8→      return saved === 'true';
 9→    }
10→    // Fall back to system preference
11→    return window.matchMedia('(prefers-color-scheme: dark)').matches;
12→  });
13→
14→  useEffect(() => {
15→    // Apply dark class to document
16→    document.documentElement.classList.toggle('dark', isDark);
17→
18→    // Save preference
19→    localStorage.setItem('darkMode', String(isDark));
20→  }, [isDark]);
21→
22→  // Listen for system preference changes
23→  useEffect(() => {
24→    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
25→    const handleChange = (e: MediaQueryListEvent) => {
26→      // Only auto-switch if user hasn't set a preference
27→      const saved = localStorage.getItem('darkMode');
28→      if (saved === null) {
29→        setIsDark(e.matches);
30→      }
31→    };
32→
33→    mediaQuery.addEventListener('change', handleChange);
34→    return () => mediaQuery.removeEventListener('change', handleChange);
35→  }, []);
36→
37→  const toggleDarkMode = useCallback(
38→    (event?: React.MouseEvent) => {
39→      const newIsDark = !isDark;
40→
41→      const applyTheme = () => {
42→        document.documentElement.classList.toggle('dark', newIsDark);
43→        localStorage.setItem('darkMode', String(newIsDark));
44→        setIsDark(newIsDark);
45→      };
46→
47→      // Skip animation if no event, no View Transition API, or user prefers reduced motion
48→      const startViewTransition = (
49→        document as { startViewTransition?: (cb: () => void) => { ready: Promise<void> } }
50→      ).startViewTransition;
51→      if (
52→        !event ||
53→        !startViewTransition ||
54→        window.matchMedia('(prefers-reduced-motion: reduce)').matches
55→      ) {
56→        applyTheme();
57→        return;
58→      }
59→
60→      const x = event.clientX;
61→      const y = event.clientY;
62→      const endRadius = Math.hypot(
63→        Math.max(x, window.innerWidth - x),
64→        Math.max(y, window.innerHeight - y),
65→      );
66→
67→      const transition = startViewTransition.call(document, applyTheme);
68→
69→      transition.ready.then(() => {
70→        document.documentElement.animate(
71→          {
72→            clipPath: [`circle(0px at ${x}px ${y}px)`, `circle(${endRadius}px at ${x}px ${y}px)`],
73→          },
74→          {
75→            duration: 500,
76→            easing: 'ease-in-out',
77→            pseudoElement: '::view-transition-new(root)',
78→          },
79→        );
80→      });
81→    },
82→    [isDark],
83→  );
84→
85→  return { isDark, toggleDarkMode };
86→}
