 50→/**
 51→ * Build a folder path string like "Parent / Child / Grandchild"
 52→ */
 53→function buildFolderPath(folderId: string, foldersById: Map<string, Folder>): string {
 54→  const parts: string[] = [];
 55→  let current = foldersById.get(folderId);
 56→  while (current) {
 57→    parts.unshift(current.name);
 58→    current = current.parentId ? foldersById.get(current.parentId) : undefined;
 59→  }
 60→  return parts.join(' / ');
 61→}
