 63→/**
 64→ * Map language code to a human-readable language name for prompt instructions
 65→ */
 66→function getLanguageName(lang: string): string {
 67→  const map: Record<string, string> = {
 68→    en: 'English',
 69→    zh: '中文',
 70→    zh_TW: '繁體中文',
 71→    ja: '日本語',
 72→    ko: '한국어',
 73→    ar: 'العربية',
 74→    es: 'Español',
 75→    fr: 'Français',
 76→    pt: 'Português',
 77→    ru: 'Русский',
 78→  };
 79→  return map[lang] || 'English';
 80→}
