  border: 1px solid rgba(255, 255, 255, 0.12);
  transform: rotate(45deg);
}

.gv-pm-confirm[data-side='left']::after {
  right: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-left: none;
  border-bottom: none;
}

.gv-pm-confirm[data-side='right']::after {
  left: -6px;
  top: 50%;
  transform: translateY(-50%) rotate(45deg);
  border-right: none;
  border-top: none;
}

.gv-pm-drag {
  width: 10px;
  height: 14px;
  margin-left: -6px;
  margin-right: 6px;
  position: relative;
  opacity: 0.7;
  cursor: move;
}

.gv-pm-drag::before {
  content: '⠿';
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
}

.gv-locked .gv-pm-drag {
  cursor: default;
  opacity: 0.9;
}

