/* ========================================
   PM Theme Toggle
   ======================================== */

.gv-pm-theme-toggle {
  width: 38px;
  height: 20px;
  border-radius: 999px;
  position: relative;
  cursor: pointer;
  flex-shrink: 0;
  border: none;
  padding: 0;
  background: linear-gradient(135deg, oklch(0.82 0.12 80), oklch(0.75 0.14 55));
  box-shadow:
    inset 0 1px 2px oklch(0 0 0 / 0.08),
    0 1px 3px oklch(0 0 0 / 0.06);
  transition:
    background 0.4s cubic-bezier(0.4, 0, 0.2, 1),
    box-shadow 0.3s ease;
  outline: none;
}

.gv-pm-theme-toggle::before {
  content: '';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: white;
  box-shadow: 0 1px 4px oklch(0 0 0 / 0.18);
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.gv-pm-theme-toggle::after {
  content: '☀';
  position: absolute;
  top: 50%;
  left: 3px;
  transform: translateY(-50%);
  font-size: 11px;
  line-height: 1;
  pointer-events: none;
  transition:
    opacity 0.3s ease,
    transform 0.3s ease;
  opacity: 1;
}

.gv-pm-theme-toggle:hover {
  box-shadow:
    inset 0 1px 2px oklch(0 0 0 / 0.1),
