.gv-aistudio .gv-conversation-remove-btn .google-symbols,
.gv-aistudio .gv-folder-uncategorized-header .google-symbols {
  font-family: inherit !important;
  /* Don’t rely on Material Symbols in aistudio */
  font-weight: 400;
  font-size: 0;
  /* Hide text like 'push_pin' */
  line-height: 20px;
  display: inline-block;
  width: 20px;
  /* bigger box to avoid clipping */
  height: 20px;
  overflow: hidden;
  vertical-align: middle;
}

.gv-aistudio .google-symbols::before {
  display: block;
  width: 20px;
  height: 20px;
  line-height: 20px;
  text-align: center;
  font-size: 18px;
}

/* Per-icon mappings */
.gv-aistudio .google-symbols[data-icon='expand_more']::before {
  content: '▾';
}

.gv-aistudio .google-symbols[data-icon='chevron_right']::before {
