(async () => {
  try {
    const result = await browser.storage.sync.get(STORAGE_KEYS.theme);
    const saved = result[STORAGE_KEYS.theme];
    if (saved === 'light' || saved === 'dark') {
      applyPMTheme(saved);
    }
  } catch {
    // Ignore — keep detected theme
  }
})();

