.gv-hidden {
  display: none !important;
}

.gv-pm-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 18px;
  gap: 6px;
  border-bottom: 1px solid oklch(0.92 0.004 250 / 0.5);
  cursor: default;
}

@media (prefers-color-scheme: dark) {
  .gv-pm-header {
    border-bottom-color: oklch(0.3 0.008 285 / 0.5);
  }
}

.gv-pm-title {
  font-weight: 800;
  font-size: 17px;
  letter-spacing: -0.02em;
  color: oklch(0.14 0.004 285);
  flex: 1;
  min-width: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  position: relative;
  z-index: 1;
}

@media (prefers-color-scheme: dark) {
  .gv-pm-title {
    color: oklch(0.92 0.004 250);
  }
}

.theme-host.dark-theme .gv-pm-title,
body.dark-theme .gv-pm-title {
  color: oklch(0.92 0.004 250);
}

.theme-host.light-theme .gv-pm-title,
body.light-theme .gv-pm-title {
  color: oklch(0.14 0.004 285);
}

.gv-pm-title-row {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  min-width: 0;
}

.gv-pm-version {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 9px;
  flex-shrink: 0;
  position: relative;
  border-radius: 999px;
  background: oklch(0.95 0.004 250 / 0.6);
  color: oklch(0.4 0.006 250);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.01em;
  text-decoration: none;
  border: 1px solid oklch(0.92 0.004 250 / 0.5);
  box-shadow: 0 1px 4px oklch(0 0 0 / 0.04);
  transition:
    transform 120ms cubic-bezier(0.4, 0, 0.2, 1),
    box-shadow 160ms ease,
    background 160ms ease,
    border-color 160ms ease;
  white-space: nowrap;
}

.gv-pm-version:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px oklch(0 0 0 / 0.08);
  border-color: oklch(0.55 0.17 155 / 0.4);
  background: oklch(0.95 0.004 250 / 0.8);
}

.gv-pm-version-outdated {
  border-color: oklch(0.55 0.17 155 / 0.6);
}

.gv-pm-version-outdated::after {
  content: 'NEW';
  position: absolute;
  top: -14px;
  right: -2px;
  transform: translateX(35%);
  padding: 3px 7px;
  border-radius: 10px;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0.06em;
  color: oklch(0.95 0.02 95);
  background: linear-gradient(120deg, oklch(0.76 0.18 50), oklch(0.68 0.2 30));
  box-shadow: 0 8px 18px oklch(0 0 0 / 0.16);
  animation: gv-pm-float 1.8s ease-in-out infinite;
  pointer-events: none;
  white-space: nowrap;
}

@keyframes gv-pm-float {
  0%,
  100% {
    transform: translateY(0);
    opacity: 1;
  }

  50% {
    transform: translateY(-2px);
    opacity: 0.92;
  }
}

@media (prefers-color-scheme: dark) {
  .gv-pm-title-row {
    color: oklch(0.92 0.004 250);
  }

  .gv-pm-version {
    background: oklch(0.26 0.008 285 / 0.7);
    color: oklch(0.72 0.006 250);
    border-color: oklch(0.3 0.008 285 / 0.6);
    box-shadow: 0 1px 4px oklch(0 0 0 / 0.2);
  }

  .gv-pm-version:hover {
    border-color: oklch(0.7 0.16 155 / 0.5);
    background: oklch(0.28 0.008 285 / 0.8);
  }

  .gv-pm-version-outdated::after {
    background: linear-gradient(120deg, oklch(0.72 0.18 45), oklch(0.62 0.2 28));
    color: oklch(0.98 0.01 96);
    box-shadow: 0 6px 16px oklch(0 0 0 / 0.3);
  }
}

