.gv-pm-add {
  height: 33px;
  border-radius: 10px;
  padding: 0 16px;
  background: oklch(0.55 0.17 155);
  color: oklch(0.99 0.01 155);
  border: none;
  font-weight: 700;
  box-shadow: 0 3px 10px oklch(0.55 0.17 155 / 0.35);
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  overflow: hidden;
}

.gv-pm-add::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.5);
  transform: translate(-50%, -50%);
  transition:
    width 0.6s,
    height 0.6s;
}

.gv-pm-add:active::before {
  width: 300px;
  height: 300px;
  transition:
    width 0s,
    height 0s;
}

.gv-pm-add:hover {
  background: oklch(0.6 0.2 158);
  box-shadow: 0 6px 18px oklch(0.55 0.17 155 / 0.45);
  transform: translateY(-2px);
}

